.darma-loader-darma-custom-472 {
   width: calc(5*24px);
   height: 42px;
   display: flex;
   color: var(--loader-color, #be123c);
   filter: drop-shadow(30px 25px 0 currentColor) drop-shadow(60px 0 0 currentColor) drop-shadow(120px 0 0 currentColor);
   clip-path: inset(0 100% 0 0);
   animation: darma-loader-darma-custom-472-l12 2s infinite steps(7);
}
.darma-loader-darma-custom-472:before  {
  content: "";
   width: 24px;
   height: 20px;
   --c:no-repeat radial-gradient(farthest-side,currentColor 92%,#0000);
   background: var(--c) left /70% 70%, var(--c) right/20% 20%, var(--c) top 0 right 15%/20% 20%, var(--c) bottom 0 right 15%/20% 20%;
}
@keyframes darma-loader-darma-custom-472-l12  {
  100% {clip-path: inset(0 -30px 0 0)}
}

